+
+        match mouse.phase {
+            MousePhase::Move | MousePhase::Drag | MousePhase::Down => {
+                self.set_hover_from_xy(mouse.x, mouse.y);
+            }
+            MousePhase::Up => {}
+        }
+
+        if mouse.phase == MousePhase::Down {
+            let link_id = self.link_id_at_xy(mouse.x, mouse.y);
+            if link_id != 0 {
